.studies-page {
  min-width: 100vw;
  min-height: 100vh;
  background: var(--color-bg);
}

.cs-row {
  width: 100%;
  padding: 1em;
  display: flex;
  justify-content: flex-end;
}

.cs-item {
  width: 30%;
  margin-right: 20%;
}

.cs-item-sm {
  width: 25%;
  margin-right: 10%;
  overflow: hidden;
  background: var(--color-accent-bg);
}

.cs-item-sm .cs-img {
  position: relative;
  height: 500px;
}

.cs-item-sm .cs-img img {
  transform: scale(0.5);
}

.cs-item-sm .cs-copy {
  position: absolute;
  bottom: 1em;
  left: 1em;
}

@media (max-width: 900px) {
  .cs-item {
    width: 100%;
    margin-right: 0;
  }

  .cs-item-sm {
    margin-right: 0;
  }
}

.case-study-page {
  min-width: 100vw;
  min-height: 100vh;
  background: var(--color-bg);
}

.study-prev {
  display: flex;
  padding: 1em;
  gap: 5em;
  margin-bottom: 2em;
}

.study-prev > div {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
}

.study-prev-img {
  width: 100px;
  height: 200px;
}

.study-subhero {
  padding: 1em;
}

.study-shots-2 {
  width: 100%;
  padding: 1em;
  height: 200vh;
  display: flex;
  flex-direction: column;
  gap: 1em;
}

.study-shots-2 > div {
  flex: 1;
}

.shot-row {
  display: flex;
  flex-direction: column;
  gap: 1em;
  height: 90vh;
}

.show-row-row {
  display: flex;
  gap: 1em;
  flex: 1;
  height: 50vh;
}

@media (max-width: 900px) {
  .study-prev {
    flex-direction: column;
    gap: 1em;
  }

  .study-prev-img {
    width: 100%;
  }

  .show-row-row {
    flex-direction: column;
  }

  .study-shots-2 {
    height: max-content;
  }
}

.contact-page {
  min-width: 100vw;
  min-height: 100vh;
  background: var(--color-bg);
}

.contact-form {
  width: 100%;
  padding: 1em;
  display: flex;
  justify-content: flex-end;
}

form {
  position: relative;
  width: 30%;
}

.contact-form form input {
  border: none;
  border-bottom: 1px solid var(--color-text);
  outline: none;
  padding: 0.5em 0;
  width: 100%;
}

.contact-form form ::placeholder {
  color: var(--color-text);
  font-size: 20px;
  font-weight: 300;
}

.contact-form button {
  border: none;
  outline: none;
  background: none;
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
}

.contact-subhero {
  padding: 1em;
}

@media (max-width: 900px) {
  form {
    width: 100%;
    padding-bottom: 3em;
  }
}

